// Entrada
const input = $('webhookAgendas').first().json.body;
const config = $('buscarHorariosDeTrabalho').item.json;

const date = new Date(input.data_e_hora);

// mapeamento de dias
const daysMap = [
  "domingo",
  "segunda",
  "terca",
  "quarta",
  "quinta",
  "sexta",
  "sabado"
];

const dayIndex = date.getDay();
const day = daysMap[dayIndex];

const formattedDate = date.toLocaleDateString("pt-BR", {
  timeZone: "America/Sao_Paulo",
});

const hour = input.data_e_hora.split("T")[1].slice(0, 5);

const isActive = config[`${day}_ativo`];
const start = config[`${day}_inicio_trabalho`];
const end = config[`${day}_fim_trabalho`];
const lunchStart = config[`${day}_inicio_almoco`];
const lunchEnd = config[`${day}_fim_almoco`];

const base = {
  date: formattedDate,
  hour,
  weekday: day,
};

// ------- função de achar próximo dia válido -------
function getNextAvailableDay() {
  for (let i = 1; i <= 7; i++) {
    const nextDate = new Date(date);
    nextDate.setDate(date.getDate() + i);

    const nextDayIndex = nextDate.getDay();
    const nextDayName = daysMap[nextDayIndex];

    if (config[`${nextDayName}_is_active`]) {
      const nextStart = config[`${nextDayName}_inicio_trabalho`];

      return {
        nextAvailableDate: nextDate.toLocaleDateString("pt-BR", {
          timeZone: "America/Sao_Paulo",
        }),
        nextAvailableWeekday: nextDayName,
        nextAvailableHour: nextStart
      };
    }
  }
  return null;
}


// ---------- VALIDAÇÕES ----------

if (!isActive) {
  return [{
    json: {
      valid: false,
      reason: "Dia não possui expediente.",
      ...base,
      ...getNextAvailableDay()
    }
  }];
}

if (hour < start || hour >= end) {
  return [{
    json: {
      valid: false,
      reason: "Fora do horário de atendimento.",
      ...base,
      ...getNextAvailableDay()
    }
  }];
}

if (lunchStart && lunchEnd && hour >= lunchStart && hour < lunchEnd) {
  return [{
    json: {
      valid: false,
      reason: "Horário de almoço.",
      ...base,
      ...getNextAvailableDay()
    }
  }];
}


// ---------- Se deu bom ----------
return [{
  json: {
    valid: true,
    reason: "Horário dentro do expediente.",
    ...base
  }
}];

// -------- 1. CONFIGURAÇÃO E DURAÇÃO -------- //
const request = $('webhookAgendas').first().json.body;
const requestedISO = request.data_e_hora; // "2025-12-20T14:01:00"

// Tenta pegar a duração da tabela work_schedules
let duration = 30; // Minutos padrão
try {
  const scheduleConfig = $('buscarHorariosDeTrabalho1').first().json;
  if (scheduleConfig && scheduleConfig.duracao_atendimento) {
    duration = parseInt(scheduleConfig.duracao_atendimento, 10);
  }
} catch (e) {}

// Pega os agendamentos existentes
const scheduled = $items("buscarAgendamentos").map(e => e.json);

// -------- 2. PREPARAR DADOS DO PEDIDO (Novo Agendamento) -------- //
const reqDate = new Date(requestedISO);
const reqStartMs = reqDate.getTime();
const reqEndMs = reqStartMs + (duration * 60 * 1000); // Soma duração em milissegundos

// Strings para retorno
const requestedDate = requestedISO.slice(0, 10);
const requestedTime = requestedISO.slice(11, 16);

// -------- 3. VERIFICAR CONFLITO DE INTERVALO (OVERLAP) -------- //
// A regra de ouro de conflito é: (InicioA < FimB) && (FimA > InicioB)

let conflict = null;

for (const ev of scheduled) {
  const evStart = new Date(ev.start_datetime).getTime();
  const evEnd = new Date(ev.end_datetime).getTime();

  // Verifica se encavala
  if (reqStartMs < evEnd && reqEndMs > evStart) {
    conflict = ev; // Achou um conflito!
    break; // Para de procurar
  }
}

// -------- 4. SE NÃO TIVER CONFLITO -------- //
if (!conflict) {
  return [{
    json: {
      available: true,
      status: "livre",
      requested_date: requestedDate,
      requested_time: requestedTime,
      requested_iso: requestedISO,
      duration_minutes: duration
    }
  }];
}

// -------- 5. SE ESTIVER OCUPADO -> BUSCAR PRÓXIMO SLOT -------- //
// Aqui mantemos a lógica de procurar um espaço livre após o conflito
// Começamos a busca a partir do final do agendamento que gerou o conflito

// Pega a hora que termina o conflito para sugerir como início
const conflictEnd = new Date(conflict.end_datetime);
let nextStartMs = conflictEnd.getTime();
const endOfDayLimitMs = new Date(requestedDate + "T23:00:00").getTime();

let nextFree = null;
let attempts = 0;

// Tenta achar um buraco nos próximos horários
while (nextStartMs < endOfDayLimitMs && attempts < 20) {
  attempts++;

  const potentialEndMs = nextStartMs + (duration * 60 * 1000);
  let isBlocked = false;

  // Verifica se esse "novo horário sugerido" bate com algum outro agendamento
  for (const ev of scheduled) {
    const evStart = new Date(ev.start_datetime).getTime();
    const evEnd = new Date(ev.end_datetime).getTime();

    if (nextStartMs < evEnd && potentialEndMs > evStart) {
      isBlocked = true;
      // Se bateu, pula para o fim desse agendamento impeditivo
      nextStartMs = evEnd; 
      break; 
    }
  }

  if (!isBlocked) {
    // Achamos um horário livre!
    const freeDate = new Date(nextStartMs);
    // Ajuste fuso horário simples para exibir HH:mm (Gambi segura para BRT se o server for UTC)
    // O ideal é usar .toISOString() e pegar o pedaço, mas ajustando o offset -3h
    const freeDateBR = new Date(nextStartMs - (3 * 60 * 60 * 1000)); 

    const h = String(freeDateBR.getUTCHours()).padStart(2, '0');
    const m = String(freeDateBR.getUTCMinutes()).padStart(2, '0');
    nextFree = `${h}:${m}`;
    break;
  }
}

// -------- 6. RETORNO DE OCUPADO -------- //
if (nextFree) {
  return [{
    json: {
      available: false,
      status: "ocupado",
      requested_date: requestedDate,
      requested_time: requestedTime,
      next_available_date: requestedDate,
      next_available_time: nextFree,
      next_available_iso: requestedDate + "T" + nextFree + ":00",
      conflict: conflict,
      duration: duration + " min"
    }
  }];
}

return [{
  json: {
    available: false,
    status: "ocupado",
    requested_date: requestedDate,
    requested_time: requestedTime,
    reason: "Sem horários disponíveis hoje",
    conflict: conflict,
    duration: duration + " min"
  }
}];

// -------- INPUTS REAIS -------- //

const request = $('webhookAgendas').first().json.body;
const requestedISO = request.data_e_hora;    // ex: "2025-12-04T10:00:00"

const scheduled = $items("buscarAgendamentos1").map(e => e.json);


// -------- PARSE DO HORARIO SOLICITADO (SEM TIMEZONE) -------- //

const requestedDate = requestedISO.slice(0, 10);   // "2025-12-04"
const requestedTime = requestedISO.slice(11, 16);  // "10:00"

const requestedKey = requestedDate + " " + requestedTime;


// -------- MAPA DE OCUPAÇÃO -------- //

const busy = {};

// transforma cada evento em chave uniforme
for (const ev of scheduled) {

  const d = ev.inicio.slice(0, 10);
  const t = ev.inicio.slice(11, 16);

  const key = d + " " + t;

  busy[key] = ev;
}


// -------- CHECAR CONFLITO -------- //

const conflict = busy[requestedKey] || null;

if (!conflict) {
  return [
    {
      json: {
        available: true,
        status: "livre",
        requested_date: requestedDate,
        requested_time: requestedTime,
        requested_iso: requestedISO
      }
    }
  ];
}


// -------- SE ESTÁ OCUPADO → PROCURAR PROX HORARIO -------- //

let [h, m] = requestedTime.split(":");
let hour = parseInt(h, 10);

let nextFree = null;

for (let i = 1; i <= 12; i++) {

  hour++;

  if (hour >= 24) break;

  const nextTime = String(hour).padStart(2, "0") + ":" + m;

  const key = requestedDate + " " + nextTime;

  if (!busy[key]) {
    nextFree = nextTime;
    break;
  }
}


// -------- RETORNO FINAL -------- //

if (nextFree) {
  return [
    {
      json: {
        available: false,
        status: "ocupado",
        requested_date: requestedDate,
        requested_time: requestedTime,
        next_available_date: requestedDate,
        next_available_time: nextFree,
        next_available_iso: requestedDate + "T" + nextFree + ":00",
        conflict: conflict,
        duration: "1h"
      }
    }
  ];
}

return [
  {
    json: {
      available: false,
      status: "ocupado",
      requested_date: requestedDate,
      requested_time: requestedTime,
      reason: "Sem horários disponíveis no mesmo dia",
      conflict: conflict,
      duration: "1h"
    }
  }
];

