const rawISO = body.data_e_hora;

// Tenta pegar a duração do nó anterior (Get Organization Config)
let duration = 30; // Valor padrão de segurança

try {
  // Pega o valor do banco. Se vier nulo, usa 30.
  const dbDuration = $('buscarDadosHorariosDeTrabalho').first().json.duracao_atendimento;
  if (dbDuration) {
    duration = parseInt(dbDuration, 10);
  }
} catch (error) {
  console.log("Não foi possível ler a duração do banco, usando 30min.");
}

