const timePart = rawISO.split('T')[1].substring(0, 5);

const [h, m] = timePart.split(':').map(Number);

// Criamos uma data base para somar os minutos
const dateObj = new Date(2000, 0, 1, h, m, 0);
dateObj.setMinutes(dateObj.getMinutes() + duration);

// Formatar Hora Final (HH:mm)
const endH = String(dateObj.getHours()).padStart(2, '0');
const endM = String(dateObj.getMinutes()).padStart(2, '0');
const endTimePart = `${endH}:${endM}:00`;

// -------- 3. MONTAR RETORNO -------- //
return [{
  json: {
    organization_id: body.id_organizacao,
    id_sessao: body.id_sessao,
    nome: body.nome,
    type: body.tipo_atendimento,
    email: body.email,
    phone: body.telefone,
    observacoes: body["observacoes"],

    date: datePart,
    time: timePart,

    // ISOs calculados com a duração dinâmica
    start_datetime: `${datePart}T${timePart}:00-03:00`,
    end_datetime: `${datePart}T${endTimePart}-03:00`,

    duration_used: duration // Para você conferir se pegou 120
  }
}];

