    // O ideal é usar .toISOString() e pegar o pedaço, mas ajustando o offset -3h
    const freeDateBR = new Date(nextStartMs - (3 * 60 * 60 * 1000)); 

    const h = String(freeDateBR.getUTCHours()).padStart(2, '0');
    const m = String(freeDateBR.getUTCMinutes()).padStart(2, '0');
    nextFree = `${h}:${m}`;
    break;
  }
}

// -------- 6. RETORNO DE OCUPADO -------- //
if (nextFree) {
  return [{
    json: {
      available: false,
      status: "ocupado",
      requested_date: requestedDate,
      requested_time: requestedTime,
      next_available_date: requestedDate,
      next_available_time: nextFree,
      next_available_iso: requestedDate + "T" + nextFree + ":00",
      conflict: conflict,
      duration: duration + " min"
    }
  }];
}

return [{
  json: {
    available: false,
    status: "ocupado",
    requested_date: requestedDate,
