const busy = {};

// transforma cada evento em chave uniforme
for (const ev of scheduled) {

  const d = ev.inicio.slice(0, 10);
  const t = ev.inicio.slice(11, 16);

  const key = d + " " + t;

  busy[key] = ev;
}


// -------- CHECAR CONFLITO -------- //

const conflict = busy[requestedKey] || null;

if (!conflict) {
  return [
    {
      json: {
        available: true,
        status: "livre",
        requested_date: requestedDate,
        requested_time: requestedTime,
        requested_iso: requestedISO
      }
    }
  ];
