let duration = 30; // Padrão de segurança

try {
  // Tenta ler do nó anterior que acabamos de adicionar
  const orgData = $('buscarDadosDeHorarioDeTrabalho').first().json;
  if (orgData && orgData.duracao_atendimento) {
    duration = parseInt(orgData.duracao_atendimento, 10);
  }
} catch (e) {
  // Mantém 30 se falhar
}

// -------- 3. CÁLCULO MATEMÁTICO (SEM LUXON) -------- //
const datePart = inputISO.split('T')[0];
const timePart = inputISO.split('T')[1].substring(0, 5);

const [h, m] = timePart.split(':').map(Number);

